package com.example.networking

import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

class NetworkModule {
    private val apiUrl = "https://api.example.com/users"
    private val okHttpClient: OkHttpClient = OkHttpClient.Builder()
        .connectTimeout(10, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .writeTimeout(30, TimeUnit.SECONDS)
        .build()
    private val retrofit: Retrofit = Retrofit.Builder()
        .baseUrl(apiUrl)
        .client(okHttpClient)
        .addConverterFactory(GsonConverterFactory.create())
        .build()

    fun getUserProfiles(): List<UserProfile> {
        val apiService: UserApi = retrofit.create(UserApi::class.java)
        return apiService.getUserProfiles().execute().body() ?: emptyList()
    }
}

interface UserApi {
    @GET("users")
    fun getUserProfiles(): Call<List<UserProfile>>
}

data class UserProfile(
    val id: Int,
    val name: String,
    val email: String
)